sys_script_fix.script:
(function () {
    var TABLE_NAME = 'x_1907525_rezili_0_test_table';
    var ATTACHMENT_FILE_NAME = 'dummy-test-row-1.txt';
    var ATTACHMENT_CONTENT_TYPE = 'text/plain';
    var ROWS = [
        {
            key: 'dummy-row-1',
            value: 'First dummy row',
            count: 1
        },
        {
            key: 'dummy-row-2',
            value: 'Second dummy row',
            count: 2
        }
    ];

    function info(message) {
        gs.info('[RezilientTest Seed] ' + message);
    }

    function warn(message) {
        gs.warn('[RezilientTest Seed] ' + message);
    }

    function error(message) {
        gs.error('[RezilientTest Seed] ' + message);
    }

    function validateTable() {
        var gr;

        try {
            gr = new GlideRecord(TABLE_NAME);
        } catch (e) {
            error('Unable to access ' + TABLE_NAME + ': ' + e);
            return false;
        }

        if (!gr.isValid()) {
            error('Table ' + TABLE_NAME + ' is not valid in this instance.');
            return false;
        }

        if (!gr.isValidField('u_key') ||
            !gr.isValidField('u_value') ||
            !gr.isValidField('u_count')) {
            error('Table ' + TABLE_NAME + ' is missing one or more expected ' +
                'fields: u_key, u_value, u_count.');
            return false;
        }

        return true;
    }

    function ensureRow(definition) {
        var gr = new GlideRecord(TABLE_NAME);
        var changed = false;
        var sysId = '';

        gr.addQuery('u_key', definition.key);
        gr.setLimit(1);
        gr.query();

        if (gr.next()) {
            if (String(gr.getValue('u_value') || '') !== definition.value) {
                gr.setValue('u_value', definition.value);
                changed = true;
            }

            if (String(gr.getValue('u_count') || '') !==
                String(definition.count)) {
                gr.setValue('u_count', String(definition.count));
                changed = true;
            }

            if (changed) {
                gr.update();
                return {
                    inserted: false,
                    status: 'updated',
                    record: gr
                };
            }

            return {
                inserted: false,
                status: 'unchanged',
                record: gr
            };
        }

        gr.initialize();
        gr.setValue('u_key', definition.key);
        gr.setValue('u_value', definition.value);
        gr.setValue('u_count', String(definition.count));
        sysId = String(gr.insert() || '');

        if (!sysId) {
            throw 'Insert returned an empty sys_id for key ' + definition.key;
        }

        gr.get(sysId);
        return {
            inserted: true,
            status: 'inserted',
            record: gr
        };
    }

    function attachDummyFile(rowGr) {
        var attachmentId = '';
        var attachmentText = [
            'Dummy attachment generated by a fix script.',
            'table=' + TABLE_NAME,
            'row_key=' + String(rowGr.getValue('u_key') || ''),
            'row_sys_id=' + String(rowGr.getUniqueValue() || ''),
            'generated_on=' + gs.nowDateTime()
        ].join('\n') + '\n';

        try {
            attachmentId = new GlideSysAttachment().writeBase64(
                rowGr,
                ATTACHMENT_FILE_NAME,
                ATTACHMENT_CONTENT_TYPE,
                gs.base64Encode(attachmentText)
            );
        } catch (e) {
            warn('Attachment creation failed for row ' +
                rowGr.getUniqueValue() + ': ' + e);
            return;
        }

        if (!attachmentId) {
            warn('Attachment creation returned an empty sys_id for row ' +
                rowGr.getUniqueValue() + '.');
            return;
        }

        info('Attached ' + ATTACHMENT_FILE_NAME + ' to row ' +
            rowGr.getUniqueValue() + ' (' + attachmentId + ').');
    }

    if (!validateTable()) {
        return;
    }

    var firstRowResult;
    var summaries = [];
    var i;
    var result;

    for (i = 0; i < ROWS.length; i += 1) {
        result = ensureRow(ROWS[i]);
        summaries.push(ROWS[i].key + '=' + result.status);

        if (i === 0) {
            firstRowResult = result;
        }
    }

    if (firstRowResult && firstRowResult.inserted) {
        attachDummyFile(firstRowResult.record);
    } else {
        info('First dummy row already existed; skipped attachment creation ' +
            'to avoid duplicate files.');
    }

    info('Seed complete: ' + summaries.join(', '));
})();
